import json

class NodeError(Exception):
    pass

def _log(*parts):
    print("[BAW Doc] " + " ".join(str(p) for p in parts))

def _as_model(raw):
    if isinstance(raw, dict):
        return raw
    s = str(raw or "").strip()
    if not s:
        raise NodeError("model is required (service model JSON)")
    try:
        m = json.loads(s)
    except Exception as e:
        raise NodeError("model is not valid JSON: %s" % e)
    if not isinstance(m, dict):
        raise NodeError("model must be a JSON object")
    return m

def _var_name(v):
    if isinstance(v, dict):
        return v.get("name") or v.get("variableName") or v.get("id")
    return str(v)

def _var_type(v):
    if isinstance(v, dict):
        return v.get("type") or v.get("typeName") or v.get("dataType")
    return None

def _desc_map(data_model):
    out = {}
    if isinstance(data_model, dict):
        for k, v in data_model.items():
            out[k] = (v.get("description") if isinstance(v, dict) else str(v))
    elif isinstance(data_model, list):
        for item in data_model:
            if isinstance(item, dict):
                key = item.get("name") or item.get("id") or item.get("type")
                if key:
                    out[key] = item.get("description")
    return out

def _sample_value(type_name, data):
    if not type_name:
        return ""
    t = type_name.lower()
    if t == "string":
        return ""
    if t in {"integer", "decimal"}:
        return 0
    if t in {"bool", "boolean"}:
        return False
    if t in {"date", "datetime", "time"}:
        return "12-01-1999"
    validation = data.get("validation", {}) if isinstance(data, dict) else {}
    type_obj = validation.get(type_name)
    if type_obj and isinstance(type_obj, dict):
        properties = type_obj.get("properties", {})
        if properties:
            result = {}
            for prop, prop_obj in properties.items():
                result[prop] = _sample_value(prop_obj.get("className"), data)
            return result
    return ""

def _sample_json(variables, data):
    out = {}
    if isinstance(variables, dict):
        items = list(variables.items())
    else:
        items = [(_var_name(v), v) for v in (variables or [])]
    for name, v in items:
        if not name:
            continue
        cls = v.get("className") if isinstance(v, dict) else _var_type(v)
        out[name] = _sample_value(cls, data)
    return out

